import json

results_path = "/root/.openclaw/workspace/quantized/runs/sapientinc_HRM-Text-1B-MXFP4/lm_eval_results/__root__.openclaw__workspace__quantized__sapientinc_HRM-Text-1B-MXFP4/results_2026-05-21T07-07-01.796276.json"

with open(results_path, 'r') as f:
    data = json.load(f)

results = data.get('results', {})

# Extract key metrics for each task
tasks = {
    'piqa': {},
    'hellaswag': {},
    'mmlu': {}
}

for key, val in results.items():
    if key == 'piqa':
        tasks['piqa'] = {
            'accuracy': val.get('acc,none'),
            'accuracy_stderr': val.get('acc_stderr,none')
        }
    elif key == 'hellaswag':
        tasks['hellaswag'] = {
            'accuracy': val.get('acc,none'),
            'accuracy_stderr': val.get('acc_stderr,none')
        }
    elif key.startswith('mmlu'):
        # For mmlu, we need to aggregate. For now just capture first one for checking
        pass

# For mmlu, aggregate all subtasks
mmlu_tasks = [k for k in results.keys() if k.startswith('mmlu')]
mmlu_acc = [results[k]['acc,none'] for k in mmlu_tasks if 'acc,none' in results[k]]
mmlu_stderr = [results[k].get('acc_stderr,none', 0) for k in mmlu_tasks if 'acc,none' in results[k]]

print(f"Found {len(mmlu_tasks)} MMLU subtasks")
print(f"piqa: {tasks['piqa']}")
print(f"hellaswag: {tasks['hellaswag']}")
print(f"mmlu subtask count: {len(mmlu_acc)}")

# Calculate mmlu average
if mmlu_acc:
    avg_acc = sum(mmlu_acc) / len(mmlu_acc)
    import math
    avg_stderr = math.sqrt(sum(s*s for s in mmlu_stderr)) / len(mmlu_stderr) if mmlu_stderr else None
    tasks['mmlu'] = {
        'accuracy': avg_acc,
        'accuracy_stderr': avg_stderr
    }
    print(f"mmlu aggregated: {tasks['mmlu']}")

print("\nAll tasks:", json.dumps(tasks, indent=2))
EOF

